module state_space_controller (
    input clk,
    input rst,
    input [3:0] state_input,
    output reg [3:0] control_output
);
    reg [3:0] obf_state;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            obf_state <= 4'b0000;
        end else begin
            case (obf_state)
                4'b0000: obf_state <= (state_input[0]) ? 4'b0001 : 4'b0000;
                4'b0001: obf_state <= (state_input[0]) ? 4'b0010 : 4'b0000;
                4'b0010: obf_state <= (state_input[0]) ? 4'b0011 : 4'b0001;
                4'b0011: obf_state <= (state_input[0]) ? 4'b0000 : 4'b0010;
                default: obf_state <= 4'b0000;
            endcase
        end
    end

    always @(*) begin
        control_output = obf_state;
    end
endmodule
